// Robust monkeypatch to prevent CanvasRenderingContext2D / CanvasGradient addColorStop crash
if (typeof window !== "undefined") {
  if (typeof CanvasGradient !== "undefined") {
    const originalAddColorStop = CanvasGradient.prototype.addColorStop;
    CanvasGradient.prototype.addColorStop = function (
      this: any,
      offset: number,
      color: string,
    ) {
      let parsedOffset = parseFloat(offset as any);
      if (isNaN(parsedOffset) || !isFinite(parsedOffset)) {
        console.warn(
          "Intercepted and corrected non-finite CanvasGradient addColorStop offset:",
          offset,
          color,
        );
        parsedOffset = 0;
      }
      parsedOffset = Math.max(0, Math.min(1, parsedOffset));
      try {
        originalAddColorStop.call(this, parsedOffset, color || "rgba(0,0,0,0)");
      } catch (e) {
        console.warn(
          "Caught and suppressed CanvasGradient addColorStop error:",
          e,
        );
      }
    };
  }
  if (
    typeof CanvasRenderingContext2D !== "undefined" &&
    (CanvasRenderingContext2D.prototype as any).addColorStop
  ) {
    const originalAddColorStop2 = (CanvasRenderingContext2D.prototype as any)
      .addColorStop;
    (CanvasRenderingContext2D.prototype as any).addColorStop = function (
      this: any,
      offset: number,
      color: string,
    ) {
      let parsedOffset = parseFloat(offset as any);
      if (isNaN(parsedOffset) || !isFinite(parsedOffset)) {
        console.warn(
          "Intercepted and corrected non-finite CanvasRenderingContext2D addColorStop offset:",
          offset,
          color,
        );
        parsedOffset = 0;
      }
      parsedOffset = Math.max(0, Math.min(1, parsedOffset));
      try {
        originalAddColorStop2.call(
          this,
          parsedOffset,
          color || "rgba(0,0,0,0)",
        );
      } catch (e) {
        console.warn(
          "Caught and suppressed CanvasRenderingContext2D addColorStop error:",
          e,
        );
      }
    };
  }
}

