function oklchToRgb(l: number, c: number, h: number, a: number = 1): string {
  if (isNaN(l) || isNaN(c) || isNaN(h) || isNaN(a)) {
    return "rgb(120, 120, 120)";
  }
  const hRad = (h * Math.PI) / 180;
  const L = l;
  const a_ = c * Math.cos(hRad);
  const b_ = c * Math.sin(hRad);
  return oklabToRgb(L, a_, b_, a);
}

function oklabToRgb(l: number, a_: number, b_: number, a: number = 1): string {
  if (
    isNaN(l) ||
    isNaN(a_) ||
    isNaN(b_) ||
    isNaN(a) ||
    !isFinite(l) ||
    !isFinite(a_) ||
    !isFinite(b_)
  ) {
    return "rgb(120, 120, 120)";
  }
  const L = l;
  const l_ = L + 0.3963377774 * a_ + 0.2158037573 * b_;
  const m_ = L - 0.1055613458 * a_ - 0.0638541728 * b_;
  const s_ = L - 0.0894841775 * a_ - 1.2914855414 * b_;

  const l3 = l_ * l_ * l_;
  const m3 = m_ * m_ * m_;
  const s3 = s_ * s_ * s_;

  const r_ = +4.0767416621 * l3 - 3.3077115913 * m3 + 0.2309699292 * s3;
  const g_ = -1.2684380046 * l3 + 2.6097574011 * m3 - 0.3413193965 * s3;
  const bTemp = -0.0041960863 * l3 - 0.703418614 * m3 + 1.707614701 * s3;

  const toSRGB = (x: number) => {
    if (isNaN(x) || !isFinite(x)) return 0.5;
    return x <= 0.0031308 ? 12.92 * x : 1.055 * Math.pow(x, 1 / 2.4) - 0.055;
  };

  let r = Math.max(0, Math.min(255, Math.round(toSRGB(r_) * 255)));
  let g = Math.max(0, Math.min(255, Math.round(toSRGB(g_) * 255)));
  let b = Math.max(0, Math.min(255, Math.round(toSRGB(bTemp) * 255)));

  if (isNaN(r) || isNaN(g) || isNaN(b)) {
    r = 120;
    g = 120;
    b = 120;
  }

  return a === 1 ? `rgb(${r}, ${g}, ${b})` : `rgba(${r}, ${g}, ${b}, ${a})`;
}

function translateOklchStylesInText(text: string): string {
  if (!text) return "";

  // 1. Remove interpolation space targets in gradients and other properties
  let cleaned = text.replace(
    /linear-gradient\(\s*in\s+(?:oklab|oklch)\s*,/gi,
    "linear-gradient(",
  );
  cleaned = cleaned.replace(
    /radial-gradient\(\s*in\s+(?:oklab|oklch)\s*,/gi,
    "radial-gradient(",
  );
  cleaned = cleaned.replace(
    /conic-gradient\(\s*in\s+(?:oklab|oklch)\s*,/gi,
    "conic-gradient(",
  );
  cleaned = cleaned.replace(/\bin\s+(?:oklab|oklch)\b/gi, "");

  // 2. Translate "oklch(...)" to "rgb(...)" or "rgba(...)"
  cleaned = cleaned.replace(
    /oklch\(\s*([\d\.]+%?)\s+([\d\.]+)\s+([\d\.]+)(?:\s*\/\s*([\d\.]+%?))?\s*\)/gi,
    (match, lStr, cStr, hStr, aStr) => {
      try {
        const l = lStr.endsWith("%")
          ? parseFloat(lStr) / 100
          : parseFloat(lStr);
        const c = parseFloat(cStr);
        const h = parseFloat(hStr);
        let a = 1;
        if (aStr) {
          a = aStr.endsWith("%") ? parseFloat(aStr) / 100 : parseFloat(aStr);
        }
        return oklchToRgb(l, c, h, a);
      } catch (e) {
        return "rgb(120, 120, 120)";
      }
    },
  );

  // 3. Translate "oklab(...)" to "rgb(...)" or "rgba(...)"
  cleaned = cleaned.replace(
    /oklab\(\s*([\d\.]+%?)\s+([\d\.-]+)\s+([\d\.-]+)(?:\s*\/\s*([\d\.]+%?))?\s*\)/gi,
    (match, lStr, aStr, bStr, alphaStr) => {
      try {
        const l = lStr.endsWith("%")
          ? parseFloat(lStr) / 100
          : parseFloat(lStr);
        const aVal = parseFloat(aStr);
        const bVal = parseFloat(bStr);
        let alpha = 1;
        if (alphaStr) {
          alpha = alphaStr.endsWith("%")
            ? parseFloat(alphaStr) / 100
            : parseFloat(alphaStr);
        }
        return oklabToRgb(l, aVal, bVal, alpha);
      } catch (e) {
        return "rgb(120, 120, 120)";
      }
    },
  );

  return cleaned;
}

function dataURLtoBlob(dataurl: string): Blob {
  const parts = dataurl.split(",");
  const mimeMatch = parts[0].match(/:(.*?);/);
  const mime = mimeMatch ? mimeMatch[1] : "image/png";
  const bstr = atob(parts[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) {
    u8arr[n] = bstr.charCodeAt(n);
  }
  return new Blob([u8arr], { type: mime });
}

const SYMBOL_TO_CODE: Record<string, string> = {
  R: "ZAR",
  $: "USD",
  "€": "EUR",
  "£": "GBP",
  "¥": "JPY",
  Rp: "IDR",
  R$: "BRL",
  CHF: "CHF",
  AED: "AED",
};

const CODE_TO_SYMBOL: Record<string, string> = {
  ZAR: "R",
  USD: "$",
  EUR: "€",
  GBP: "£",
  JPY: "¥",
  IDR: "Rp",
  BRL: "R$",
  CHF: "CHF",
  AED: "AED",
};

export function formatCurrency(amount: number, symbol: string): string {
  try {
    const code = SYMBOL_TO_CODE[symbol] || "USD";
    const parts = new Intl.NumberFormat(navigator.language, {
      style: "currency",
      currency: code,
    }).formatToParts(amount);

    return parts
      .map((part) => (part.type === "currency" ? symbol : part.value))
      .join("");
  } catch (e) {
    return `${symbol}${amount.toFixed(2)}`;
  }
}

