  useEffect(() => {
    // Auto-detect user's country/timezone to set optimal currency and date format
    try {
      const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone || "";
      const locale = navigator.language || "";

      let detectedCurrency = "R";
      let detectedDateFormat = "YYYY-MM-DD";

      if (timeZone.includes("America") || locale.includes("US")) {
        detectedCurrency = "$";
        detectedDateFormat = "MM/DD/YYYY";
      } else if (timeZone.includes("Europe/London") || locale.includes("GB")) {
        detectedCurrency = "£";
        detectedDateFormat = "DD/MM/YYYY";
      } else if (
        timeZone.includes("Europe") ||
        locale.includes("FR") ||
        locale.includes("DE") ||
        locale.includes("IT") ||
        locale.includes("ES") ||
        locale.includes("NL")
      ) {
        detectedCurrency = "€";
        detectedDateFormat = "DD/MM/YYYY";
      } else if (timeZone.includes("Australia") || locale.includes("AU")) {
        detectedCurrency = "A$";
        detectedDateFormat = "DD/MM/YYYY";
      } else if (timeZone.includes("Canada") || locale.includes("CA")) {
        detectedCurrency = "C$";
        detectedDateFormat = "YYYY-MM-DD";
      } else if (timeZone.includes("Africa") || locale.includes("ZA")) {
        detectedCurrency = "R";
        detectedDateFormat = "YYYY-MM-DD";
      } else {
        detectedCurrency = "$";
        detectedDateFormat = "MM/DD/YYYY";
      }

      setActiveDoc((prev) => {
        if (prev.currency === "R" && detectedCurrency !== "R") {
          return {
            ...prev,
            currency: detectedCurrency,
            dateFormat: detectedDateFormat,
          };
        }
        return prev;
      });

      setSelectedCurrency(
        detectedCurrency === "R"
          ? "ZAR"
          : detectedCurrency === "€"
            ? "EUR"
            : detectedCurrency === "£"
              ? "GBP"
              : "USD",
      );
    } catch (e) {
      console.error("Auto detect country failed", e);
    }
  }, []);

