  const handleTabChange = (tab: any) => {
    const plan = userProfile?.paymentTier || "free";
    const hasPro =
      plan === "professional" ||
      plan === "business" ||
      plan === "enterprise" ||
      userProfile?.trialActive;

    const restrictedTabs: Record<string, string> = {
      payroll: "Payroll",
      audit: "Fraud Detection",
      creditors_debtors: "Creditors & Debtors",
      catalog: "Registry & Profiles",
      workflow: "Jobs & Workflow",
      calendar: "Dispatch Calendar",
      calls: "Call Logs & Contacts",
    };

    if (!hasPro && restrictedTabs[tab]) {
      setLockedFeature(restrictedTabs[tab]);
      return;
    }
    setActiveTab(tab);
  };

