  useEffect(() => {
    const handleTimerCheck = () => {
      try {
        const raw = localStorage.getItem("gmi_app_pop_timers");
        if (!raw) {
          if (activeTimers.length > 0) setActiveTimers([]);
          return;
        }
        let timersList: any[] = JSON.parse(raw);
        let updated = false;
        let activeCountdownList: any[] = [];

        const nowMs = Date.now();
        timersList.forEach((t: any) => {
          if (t.triggered) return;

          const msLeft = t.targetTimestamp - nowMs;
          const secondsLeft = Math.max(0, Math.round(msLeft / 1000));

          if (secondsLeft <= 0) {
            // Trigger popup!
            t.triggered = true;
            updated = true;
            setTriggeredReminderPopup({
              id: t.id,
              title: t.title || "AI Action Reminder",
              message:
                t.message || "Your scheduled task reminder is active now.",
              type: t.type || "custom_alert",
            });
            handleShowAlert(`🔔 AI Reminder Popup Dispatch: ${t.title}`);
          } else {
            activeCountdownList.push({
              ...t,
              secondsLeft,
            });
          }
        });

        if (updated) {
          localStorage.setItem(
            "gmi_app_pop_timers",
            JSON.stringify(timersList),
          );
        }
        setActiveTimers(activeCountdownList);
      } catch (err) {
        console.error("Popup timer check error:", err);
      }
    };

    const intervalId = setInterval(handleTimerCheck, 1000);
    return () => clearInterval(intervalId);
  }, [activeTimers.length]);
