      const signatureUrl = activeDoc.signatureData || null;
      const pdf = await generateStructuredPDF(activeDoc, logoPreviewUrl, signatureUrl, totals);
      
      const pdfOutput = pdf.output("arraybuffer");
      if (pdfOutput.byteLength < 100) {
         throw new Error("Generated PDF is blank or invalid");
      }
      
      const pdfBlob = new Blob([pdfOutput], { type: "application/pdf" });
      const pdfUrl = URL.createObjectURL(pdfBlob);

      const docTypeSlug = (activeDoc.documentType || "document")
        .toLowerCase()
        .replace(/[^a-z0-9]/g, "-");
      const docNumSlug = (activeDoc.documentNumber || "draft")
        .replace(/[^a-zA-Z0-9-]/g, "-")
